-- ── BlackMagic.so ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$BlackMagic.so, also known as Black Magic, is an X (Twitter) growth, analytics, and personal CRM tool built by indie developer Tony Dinh; it is unrelated to the camera and video hardware company Blackmagic Design, and the service has announced it is winding down, with paid accounts ending around July 1, 2026.$q$, short_description),
  pricing_model = COALESCE($q$subscription$q$, pricing_model),
  starting_price = COALESCE($q$Historically offered a free plan alongside paid tiers reported around $9.99-$74.99/month before the service announced it is shutting down$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE($q$Independent project, originally run by a single founder$q$, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$BlackMagic.so Review: Features, Pricing, Status$q$, seo_title),
  seo_meta_description = COALESCE($q$BlackMagic.so is a Twitter/X growth and analytics tool, unrelated to Blackmagic Design. See what it offered, pricing, and its shutdown status.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$BlackMagic.so, also known simply as Black Magic, is a browser-based analytics, growth, and personal CRM tool built specifically for X (formerly Twitter), created by independent developer Tony Dinh. It is an entirely separate product from Blackmagic Design, the Australian broadcast and cinema camera hardware company behind DaVinci Resolve and the Blackmagic Cinema Camera line; the two share only a similar name and have no corporate relationship. BlackMagic.so began in May 2021 as a small script Tony Dinh built to display a progress bar around his own Twitter profile picture as his follower count grew, and it expanded from there into a fuller toolkit including the Magic Sidebar, a browser extension adding analytics and productivity panels inside the Twitter/X interface, real-time tweet and account analytics, a personal CRM for tracking interactions with followers and contacts, tweet scheduling and publishing tools, and features such as a real-time follower-count banner and a sleep indicator showing when a user is inactive. The product grew from a side project to roughly 14,000 dollars in monthly recurring revenue at its peak and was later sold by Tony Dinh in a deal reported at 128,000 dollars after rising X/Twitter API pricing made the standalone tool less profitable to run independently. As of mid-2026, the BlackMagic.so website displays a shutdown notice stating that the service is winding down and that all remaining paid subscriptions will be automatically terminated, with an end date of July 1, 2026; the notice directs existing paying subscribers to contact support at support@blackmagic.so for refund questions or alternative product suggestions. Historically, BlackMagic.so offered a free plan alongside paid tiers reported at roughly 9.99, 19.99, and 74.99 dollars per month for Personal, Professional, and Business plans respectively, targeted at individual creators, influencers, and small teams doing Twitter/X growth and community management. Because the product has ceased or is ceasing operations, it should be treated as a discontinued, sunsetting tool rather than an actively available SaaS product, and anyone researching Twitter/X growth and analytics tools should look at active alternatives rather than sign up for BlackMagic.so.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '554ba712-0d17-49af-a355-1b54add650cf';

