UPDATE tools SET
  short_description = COALESCE($q$Bleemeo is a French, Prometheus-native infrastructure and application monitoring platform that provides metrics collection, log management, uptime checks, alerting, and dashboards as a fully managed SaaS, positioned as an alternative to self-hosting Prometheus and Grafana.$q$, short_description),
