-- ── Blend ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Blend, operated by publicly traded Blend Labs, Inc. (NYSE: BLND), is a digital origination platform that helps banks, credit unions, and mortgage lenders process mortgage and consumer banking loans online.$q$, short_description),
  pricing_model = COALESCE($q$usage-based$q$, pricing_model),
  starting_price = COALESCE($q$Custom, usage-based pricing; historically around $78-84 in platform fees per funded mortgage loan, plus fees for consumer banking transactions$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$approximately 680 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Blend Review 2026: Pricing, Features for Mortgage Lenders$q$, seo_title),
  seo_meta_description = COALESCE($q$Blend powers digital mortgage and consumer banking origination for banks and credit unions. See features, pricing model, pros, cons, and FAQs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Blend Labs, Inc. (NYSE: BLND) is a publicly traded fintech company founded in 2012 by Nima Ghamsari, Eugene Marinelli, and Rosco Hill, and headquartered in San Francisco, California. The company operates Blend, a digital origination platform used by banks, credit unions, independent mortgage banks, and mortgage servicers to move mortgage and consumer banking loan applications online, replacing paper-heavy origination workflows with a digital, guided process for consumers and loan officers. Blend went public on the New York Stock Exchange in July 2021, pricing its IPO at 18 dollars per share and raising roughly 360 million dollars, valuing the company at over 4 billion dollars at the time. The company reports that its platform has processed several trillion dollars in cumulative loan applications, and that 39 of the top 100 US Federal Reserve-regulated financial institutions and 7 of the top 10 US credit unions use its software. Blend's product portfolio is organized into two main suites: the Home Lending Suite, covering mortgage origination, income and asset verification, tools for loan officers, digital closing, and rapid refinance and home equity products; and the Consumer Banking Suite, covering digital deposit account opening and consumer loan origination. In 2025 and 2026 the company introduced Blend Autopilot, an AI agent designed to automate parts of the loan origination review process, with the company reporting it can complete certain loan origination reviews in as little as 15 seconds and citing early customer adoption. Blend generates revenue primarily on a usage and transaction basis rather than flat subscription fees: for its Mortgage Suite, Blend earns a platform fee for each loan funded through its software, reported at roughly 78 to 84 dollars in economic value per funded loan in recent quarters, plus incremental fees for add-on services such as income verification delivered through partners on its platform; the Consumer Banking Suite similarly earns fees tied to account openings and completed transactions. As of the most recent employee counts, Blend Labs has approximately 680 employees. Because Blend sells to regulated financial institutions rather than consumers directly, it does not publish flat public pricing, and prospective bank and credit union customers work with Blend's sales team to scope pricing based on loan volume and modules used.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'd5455709-cf29-432c-94eb-031f95b97e84';

